{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 3f);
var fissureDepth = GetFloat(parameters, "fissureDepth", 0.6f);
var roughness = GetFloat(parameters, "roughness", 0.5f);
var mossAmount = GetFloat(parameters, "mossAmount", 0.2f);
var barkColor = GetColor(parameters, "barkColor", Color.FromRgb(120, 85, 60));
var darkBark = GetColor(parameters, "darkBarkColor", Color.FromRgb(70, 50, 35));
var mossColor = GetColor(parameters, "mossColor", Color.FromRgb(80, 110, 60));
var brightness = GetFloat(parameters, "brightness", 0f);
var contrast = GetFloat(parameters, "contrast", 0f);
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var bR = barkColor.R / 255f; var bG = barkColor.G / 255f; var bB = barkColor.B / 255f;
var dR = darkBark.R / 255f; var dG = darkBark.G / 255f; var dB = darkBark.B / 255f;
var mR = mossColor.R / 255f; var mG = mossColor.G / 255f; var mB = mossColor.B / 255f;

var period = Math.Max(1, (int)MathF.Round(scale * 2f));

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Vertical stretch: bark has strong vertical grain
    var su = u * scale;
    var sv = v * scale * 0.3f;

    // Vertical fissure noise (stretched vertically)
    var fissureNoise = TileableFractalNoise(su, sv, period, 3, 0.6f, 2.2f, seed);

    // Horizontal cross-grain for horizontal cracks
    var crossGrain = TileableFractalNoise(
        su * 1.5f + 50f, v * scale * 2f + 50f,
        period, 2, 0.5f, 2f, seed + 100);

    // Vertical streak pattern
    var streak = TileableFractalNoise(
        su * 2f, sv * 4f,
        period, 2, 0.5f, 2f, seed + 200);

    // Combined bark texture
    var barkTex = fissureNoise * 0.5f + crossGrain * 0.3f + streak * 0.2f;

    // Detect vertical fissures (sharp dark lines)
    var fissureV = TileableFractalNoise(
        su * 3f, sv * 6f,
        Math.Max(1, period / 2), 2, 0.5f, 2.5f, seed + 300);
    var fissure = MathF.Abs(fissureV - 0.5f) * 2f;
    fissure = MathF.Pow(fissure, 1.5f) * fissureDepth;
    fissure = Math.Clamp(fissure, 0f, 1f);

    // Horizontal crack lines
    var crackH = TileableFractalNoise(
        su * 2f + 200f, sv * 8f + 200f,
        Math.Max(1, period / 2), 1, 0.5f, 2f, seed + 400);
    var crack = MathF.Max(0f, (crackH - 0.6f) / 0.4f) * fissureDepth * 0.5f;

    // Surface roughness
    var roughDetail = TileableFractalNoise(
        u * scale * 6f, v * scale * 6f,
        Math.Max(1, period / 2), 2, 0.5f, 2f, seed + 500);
    var rough = (roughDetail - 0.5f) * roughness * 0.2f;

    // Base bark color with texture
    var r = Lerp(dR, bR, barkTex) + rough;
    var g = Lerp(dG, bG, barkTex) + rough * 0.85f;
    var b = Lerp(dB, bB, barkTex) + rough * 0.7f;

    // Darken fissures
    r -= fissure * 0.3f;
    g -= fissure * 0.25f;
    b -= fissure * 0.2f;

    // Add horizontal crack darkness
    r -= crack * 0.2f;
    g -= crack * 0.15f;
    b -= crack * 0.1f;

    // Moss/lichen patches
    if (mossAmount > 0.001f)
    {
        var mossNoise = TileableFractalNoise(
            u * scale * 2f + 300f, v * scale * 2f + 300f,
            period, 2, 0.5f, 2f, seed + 600);
        var mossPatch = TileableFractalNoise(
            u * scale * 0.8f, v * scale * 0.8f,
            period, 1, 0.5f, 2f, seed + 700);

        var moss = MathF.Max(0f, (mossNoise - 0.4f) / 0.6f);
        moss *= mossPatch > 0.5f ? 1f : 0f;

        // Moss grows more in horizontal cracks
        moss *= 1f + crack * 2f;

        var mossBlend = Math.Clamp(moss * mossAmount * 2f, 0f, 1f);
        var mossR = mR + (mossPatch - 0.5f) * 0.1f;
        var mossG = mG + (mossPatch - 0.5f) * 0.15f;

        r = Lerp(r, mossR, mossBlend);
        g = Lerp(g, mossG, mossBlend);
        b = Lerp(b, mB, mossBlend);
    }

    // Brightness and contrast
    r = Math.Clamp(r + brightness, 0f, 1f);
    g = Math.Clamp(g + brightness, 0f, 1f);
    b = Math.Clamp(b + brightness, 0f, 1f);

    if (MathF.Abs(contrast) > 0.001f)
    {
        var factor = 1f + contrast;
        r = (r - 0.5f) * factor + 0.5f;
        g = (g - 0.5f) * factor + 0.5f;
        b = (b - 0.5f) * factor + 0.5f;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
